sql:
SELECT SUM(annual_budget) AS total_annual_budget_seed_units
FROM ah_units
WHERE district_id = 0 AND unit_type = 'seed';

SELECT campaign_name, total_area_converted, status
FROM jlg_campaigns
WHERE status = 'completed';

external_knowledge:
- 'Harvests reaped' metaphorically refers to the outcomes or results of a campaign; 
- 'Land cultivated' represents the 'total_area_converted'; 
- 'Enterprises sprouted' symbolizes the 'number_of_enterprises_formed'; 
- 'AH units launched' corresponds to the 'number_of_ah_units_started'; 
- 'Finished campaign' refers to a campaign with a 'completed' status.

sql:
SELECT number_of_members
FROM jlg_participation
WHERE campaign_id = 1;

SELECT campaign_name, total_area_converted
FROM jlg_campaigns
ORDER BY total_area_converted DESC;

SELECT enterprise_type, SUM(investment_amount) AS total_investment
FROM enterprises
GROUP BY enterprise_type;

SELECT campaign_id, SUM(annual_budget) AS total_campaign_budget
   FROM ah_units
   GROUP BY campaign_id;

SELECT campaign_name, SUM(budget) AS total_budget, SUM(number_of_participants) AS total_participants
FROM jlg_campaigns
GROUP BY campaign_name;

external_knowledge:
Kollam district; 
JLGs stand for Joint Liability Groups, which are informal groups of individuals formed to facilitate collective activity or interest; 
AH units refer to Animal Husbandry units; 
Campaigns in this context refer to initiatives or programs aimed at promoting agricultural development and facilitating the formation of JLGs and AH units in the district; 
Annual revenue is the total income generated by the enterprises formed during the campaign period.

sql:
SELECT unit_type, number_of_beneficiaries
FROM ah_units
WHERE annual_budget > 50000;
